module watchdog_timer (  
    input wire clk,  
    input wire reset,  
    input wire [3:0] timeout_value,  
    output reg timeout_signal  
);  
    reg [3:0] current_count;  

    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            current_count <= 4'b0000;  
            timeout_signal <= 1'b0;  
        end else begin  
            if (current_count < timeout_value) begin  
                current_count <= current_count + 1;  
                timeout_signal <= 1'b0;  
            end else begin  
                timeout_signal <= 1'b1;  
            end  
        end  
    end  
endmodule
